                        }
                        if(count &gt; 10){
                            break;
                        }
                    }
                }

            }
        });
        thread.start();
        synchronized(lock){
            while (true){
                System.out.println(Thread.currentThread().getName()+":"+count);
                count++;
                if(count==5){
                    lock.wait();
                }
                if(count&gt;10){
                    break;
                }
            }
        }
    }

}

</code></pre>

<ol>
<li>wait，notify方法都属于Object对象。</li>
